import React, { useState, useMemo, useCallback, useEffect } from 'react';
import { Link } from 'react-router-dom';
import {
  GoabText,
  GoabButton,
  GoabButtonGroup,
  GoabTabs,
  GoabTab,
  GoabFormItem,
  GoabInput,
  GoabFilterChip,
  GoabTable,
  GoabTableSortHeader,
  GoabCheckbox,
  GoabBadge,
  GoabIcon,
  GoabDropdown,
  GoabDropdownItem,
  GoabDrawer,
  GoabModal,
  GoabDivider,
  GoabDataGrid,
  GoabPopover
} from '@abgov/react-components';
import { usePageHeader } from '../contexts/PageHeaderContext';
import { ScrollContainer } from '../components/ScrollContainer';
import { filterData, sortData } from '../utils/searchUtils';
import { getPriorityBadgeProps } from '../utils/badgeUtils';
import { mockFetch } from '../utils/mockApi';
import mockData from '../data/mockCases.json';
import emptyStateIllustration from '../assets/empty-state-illustration.svg';

interface Case {
  id: string;
  name: string;
  status: string;
  statusText: string;
  priority: 'high' | 'medium' | 'low';
  dueDate: string;
  assignedTo: string;
  jurisdiction: string;
  fileNumber: string;
  category: string;
  selected?: boolean;
}

export function CasesPage() {
  // Page header with actions
  const headerActions = useMemo(() => (
    <GoabButtonGroup gap="compact" alignment="start">
      <GoabButton type="secondary" size="compact">Export</GoabButton>
      <GoabButton type="primary" size="compact">Add case</GoabButton>
    </GoabButtonGroup>
  ), []);
  usePageHeader('Cases', headerActions);

  // Data state
  const [cases, setCases] = useState<Case[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  // Filter state
  const [activeTab, setActiveTab] = useState('all');
  const [inputValue, setInputValue] = useState('');
  const [inputError, setInputError] = useState('');
  const [typedChips, setTypedChips] = useState<string[]>([]);
  const [sortConfig, setSortConfig] = useState<{ key: keyof Case | ''; direction: 'asc' | 'desc' | 'none' }>({
    key: '',
    direction: 'none'
  });

  // Drawer filter state
  const [filterDrawerOpen, setFilterDrawerOpen] = useState(false);
  const [pendingFilters, setPendingFilters] = useState({
    status: [] as string[],
    priority: [] as string[],
    assignedTo: [] as string[]
  });
  const [appliedFilters, setAppliedFilters] = useState({
    status: [] as string[],
    priority: [] as string[],
    assignedTo: [] as string[]
  });

  // Modal state
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [caseToDelete, setCaseToDelete] = useState<string | null>(null);

  // Fetch data
  useEffect(() => {
    const fetchCases = async () => {
      setIsLoading(true);
      const data = await mockFetch<Case[]>(mockData as Case[]);
      setCases(data);
      setIsLoading(false);
    };
    fetchCases();
  }, []);

  // Extract filter options from data
  const filterOptions = useMemo(() => ({
    statuses: [...new Set(cases.map(c => c.statusText))].sort(),
    priorities: ['high', 'medium', 'low'],
    assignees: [...new Set(cases.map(c => c.assignedTo))].sort()
  }), [cases]);

  // Filter and sort
  const filteredCases = useMemo(() => {
    let filtered = cases;

    // Tab filter
    if (activeTab !== 'all') {
      filtered = filtered.filter(c => c.category === activeTab);
    }

    // Search chips
    filtered = filterData(typedChips, filtered);

    // Drawer filters
    if (appliedFilters.status.length > 0) {
      filtered = filtered.filter(c => appliedFilters.status.includes(c.statusText));
    }
    if (appliedFilters.priority.length > 0) {
      filtered = filtered.filter(c => appliedFilters.priority.includes(c.priority));
    }
    if (appliedFilters.assignedTo.length > 0) {
      filtered = filtered.filter(c => appliedFilters.assignedTo.includes(c.assignedTo));
    }

    return sortData(filtered, sortConfig.key, sortConfig.direction);
  }, [cases, activeTab, typedChips, sortConfig, appliedFilters]);

  // Selection state
  const selectedCount = useMemo(() =>
    filteredCases.filter(c => c.selected).length,
    [filteredCases]
  );
  const isAllSelected = selectedCount > 0 && selectedCount === filteredCases.length;
  const isIndeterminate = selectedCount > 0 && selectedCount < filteredCases.length;

  // Handlers
  const applyFilter = (valueOverride?: string) => {
    const value = valueOverride ?? inputValue;
    const trimmed = value.trim();
    if (!trimmed) {
      setInputError('Search field empty');
      return;
    }
    if (typedChips.includes(trimmed)) {
      setInputError('Already added');
      return;
    }
    setTypedChips([...typedChips, trimmed]);
    setInputValue('');
    setInputError('');
  };

  const togglePendingFilter = (category: keyof typeof pendingFilters, value: string) => {
    setPendingFilters(prev => ({
      ...prev,
      [category]: prev[category].includes(value)
        ? prev[category].filter(v => v !== value)
        : [...prev[category], value]
    }));
  };

  const applyFilters = () => {
    setAppliedFilters(pendingFilters);
    setFilterDrawerOpen(false);
  };

  const clearAllFilters = () => {
    setTypedChips([]);
    setAppliedFilters({ status: [], priority: [], assignedTo: [] });
    setPendingFilters({ status: [], priority: [], assignedTo: [] });
  };

  // Note: onSort receives detail object directly, not wrapped in event
  const handleSort = (detail: { sortBy: string; sortDir: number }) => {
    const { sortBy, sortDir } = detail;
    setSortConfig({
      key: sortBy as keyof Case,
      direction: sortDir === 1 ? 'asc' : sortDir === -1 ? 'desc' : 'none'
    });
  };

  const confirmDelete = () => {
    if (caseToDelete) {
      setCases(cases.filter(c => c.id !== caseToDelete));
    }
    setShowDeleteModal(false);
    setCaseToDelete(null);
  };

  // Build filter chips for display
  const filterChips = useMemo(() => {
    const chips: { category: string; value: string; label: string }[] = [];
    appliedFilters.status.forEach(v => chips.push({ category: 'status', value: v, label: v }));
    appliedFilters.priority.forEach(v => chips.push({ category: 'priority', value: v, label: `${v.charAt(0).toUpperCase() + v.slice(1)} priority` }));
    appliedFilters.assignedTo.forEach(v => chips.push({ category: 'assignedTo', value: v, label: v }));
    return chips;
  }, [appliedFilters]);

  return (
    <div style={{ maxWidth: '100%', overflow: 'hidden', paddingBottom: '32px' }}>
      {/* Filter section */}
      <div className="clients-content-padding">
        <div className="clients-filter-section">
          <GoabTabs initialTab={1} onChange={(detail) => {
            // onChange receives detail object directly with { tab: number }
            const tabMap = ['all', 'todo', 'progress', 'complete'];
            setActiveTab(tabMap[detail.tab - 1]);
          }}>
            <GoabTab heading="All" />
            <GoabTab heading="To do" />
            <GoabTab heading="In progress" />
            <GoabTab heading="Complete" />
          </GoabTabs>

          <GoabFormItem error={inputError} labelSize="compact">
            <div className="clients-search-row">
              <div className="clients-search-group">
                <GoabInput
                  name="filterInput"
                  value={inputValue}
                  leadingIcon="search"
                  width="100%"
                  size="compact"
                  placeholder="Search..."
                  onChange={(e) => { setInputValue(e.value); setInputError(''); }}
                  onKeyPress={(e) => e.key === 'Enter' && applyFilter(e.value)}
                />
                <GoabButton type="tertiary" size="compact" onClick={() => applyFilter()}>
                  Search
                </GoabButton>
              </div>
              <div className="clients-actions-group">
                <GoabDropdown
                  value={sortConfig.key}
                  onChange={(e) => setSortConfig({ key: e.value as keyof Case, direction: 'asc' })}
                  placeholder="Sort by"
                  size="compact"
                  width="160px"
                >
                  <GoabDropdownItem value="dueDate" label="Due date" />
                  <GoabDropdownItem value="priority" label="Priority" />
                  <GoabDropdownItem value="status" label="Status" />
                </GoabDropdown>
                <GoabButton
                  type="tertiary"
                  leadingIcon="filter"
                  size="compact"
                  onClick={() => { setPendingFilters(appliedFilters); setFilterDrawerOpen(true); }}
                >
                  Filter
                </GoabButton>
              </div>
            </div>
          </GoabFormItem>
        </div>

        {/* Filter chips */}
        {(typedChips.length > 0 || filterChips.length > 0) && (
          <div className="clients-chips-container">
            <GoabIcon type="filter" size="small" fillColor="var(--goa-color-text-secondary)" mr="2xs" />
            {typedChips.map(chip => (
              <GoabFilterChip key={`search-${chip}`} content={chip} onClick={() => setTypedChips(prev => prev.filter(c => c !== chip))} />
            ))}
            {filterChips.map(chip => (
              <GoabFilterChip
                key={`${chip.category}-${chip.value}`}
                content={chip.label}
                onClick={() => setAppliedFilters(prev => ({
                  ...prev,
                  [chip.category]: prev[chip.category as keyof typeof prev].filter(v => v !== chip.value)
                }))}
              />
            ))}
            <GoabButton size="compact" type="tertiary" onClick={clearAllFilters}>Clear all</GoabButton>
          </div>
        )}
      </div>

      {/* Data table */}
      <ScrollContainer>
        <div className="table-wrapper">
          <GoabDataGrid keyboardNav="table" keyboardIconPosition="right">
            <GoabTable width="100%" onSort={handleSort} variant="relaxed" striped>
              <thead>
                <tr data-grid="row">
                  <th data-grid="cell" className="goa-table-cell--checkbox">
                    <GoabCheckbox
                      name="selectAll"
                      checked={isAllSelected}
                      indeterminate={isIndeterminate}
                      onChange={() => setCases(prev => prev.map(c => ({ ...c, selected: !isAllSelected && !isIndeterminate })))}
                      ariaLabel="Select all"
                    />
                  </th>
                  <th data-grid="cell"><GoabTableSortHeader name="status">Status</GoabTableSortHeader></th>
                  <th data-grid="cell">Name</th>
                  <th data-grid="cell">Assigned to</th>
                  <th data-grid="cell"><GoabTableSortHeader name="dueDate">Due date</GoabTableSortHeader></th>
                  <th data-grid="cell">Jurisdiction</th>
                  <th data-grid="cell">File number</th>
                  <th data-grid="cell"><GoabTableSortHeader name="priority">Priority</GoabTableSortHeader></th>
                  <th data-grid="cell"></th>
                </tr>
              </thead>
              <tbody>
                {isLoading ? (
                  [...Array(10)].map((_, i) => (
                    <tr key={i} data-grid="row">
                      <td data-grid="cell"><div style={{ width: 18, height: 18, borderRadius: 4, backgroundColor: 'var(--goa-color-greyscale-200)' }} /></td>
                      <td data-grid="cell"><div style={{ height: 22, width: 80, borderRadius: 12, backgroundColor: 'var(--goa-color-greyscale-200)' }} /></td>
                      <td data-grid="cell"><div style={{ height: 14, width: '70%', borderRadius: 4, backgroundColor: 'var(--goa-color-greyscale-200)' }} /></td>
                      <td data-grid="cell"><div style={{ height: 14, width: '60%', borderRadius: 4, backgroundColor: 'var(--goa-color-greyscale-200)' }} /></td>
                      <td data-grid="cell"><div style={{ height: 14, width: '50%', borderRadius: 4, backgroundColor: 'var(--goa-color-greyscale-200)' }} /></td>
                      <td data-grid="cell"><div style={{ height: 14, width: '55%', borderRadius: 4, backgroundColor: 'var(--goa-color-greyscale-200)' }} /></td>
                      <td data-grid="cell"><div style={{ height: 14, width: '65%', borderRadius: 4, backgroundColor: 'var(--goa-color-greyscale-200)' }} /></td>
                      <td data-grid="cell"><div style={{ height: 22, width: 60, borderRadius: 12, backgroundColor: 'var(--goa-color-greyscale-200)' }} /></td>
                      <td data-grid="cell"><div style={{ width: 24, height: 24, borderRadius: 4, backgroundColor: 'var(--goa-color-greyscale-200)' }} /></td>
                    </tr>
                  ))
                ) : filteredCases.length === 0 && cases.length > 0 ? (
                  <tr>
                    <td colSpan={9} className="clients-empty-state-cell">
                      <div className="clients-empty-state">
                        <img src={emptyStateIllustration} alt="" className="clients-empty-state__illustration" />
                        <span className="clients-empty-state__heading">No results found</span>
                        <span className="clients-empty-state__subline">Try adjusting your search or filters.</span>
                        <GoabButton type="tertiary" size="compact" onClick={clearAllFilters}>Clear filters</GoabButton>
                      </div>
                    </td>
                  </tr>
                ) : (
                  filteredCases.map(caseItem => (
                    <tr key={caseItem.id} data-grid="row" aria-selected={caseItem.selected}>
                      <td data-grid="cell" className="goa-table-cell--checkbox">
                        <GoabCheckbox
                          name={`select-${caseItem.id}`}
                          checked={caseItem.selected}
                          onChange={() => setCases(prev => prev.map(c => c.id === caseItem.id ? { ...c, selected: !c.selected } : c))}
                          ariaLabel={`Select ${caseItem.name}`}
                        />
                      </td>
                      <td data-grid="cell"><GoabBadge type={caseItem.status} content={caseItem.statusText} emphasis="subtle" icon /></td>
                      <td data-grid="cell" style={{ whiteSpace: 'nowrap' }}>
                        <Link to={`/case/${caseItem.id}`} className="table-row-link">{caseItem.name}</Link>
                      </td>
                      <td data-grid="cell" style={{ whiteSpace: 'nowrap' }}>{caseItem.assignedTo}</td>
                      <td data-grid="cell" style={{ whiteSpace: 'nowrap' }}>{caseItem.dueDate}</td>
                      <td data-grid="cell" style={{ whiteSpace: 'nowrap' }}>{caseItem.jurisdiction}</td>
                      <td data-grid="cell">{caseItem.fileNumber}</td>
                      <td data-grid="cell"><GoabBadge {...getPriorityBadgeProps(caseItem.priority)} /></td>
                      <td data-grid="cell">
                        <GoabPopover target={<button className="row-action-trigger"><GoabIcon type="ellipsis-horizontal" /></button>}>
                          <div className="row-action-menu">
                            <button className="row-action-menu__item">View</button>
                            <button className="row-action-menu__item">Edit</button>
                            <button className="row-action-menu__item row-action-menu__item--destructive" onClick={() => { setCaseToDelete(caseItem.id); setShowDeleteModal(true); }}>
                              <GoabIcon type="trash" size="small" />Delete
                            </button>
                          </div>
                        </GoabPopover>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </GoabTable>
          </GoabDataGrid>
        </div>
      </ScrollContainer>

      {/* Filter drawer */}
      <GoabDrawer heading="Filter cases" position="right" open={filterDrawerOpen} maxSize="300px" onClose={() => setFilterDrawerOpen(false)}
        actions={
          <GoabButtonGroup alignment="start" gap="compact">
            <GoabButton type="primary" size="compact" onClick={applyFilters}>Apply filters</GoabButton>
            <GoabButton type="tertiary" size="compact" onClick={() => setFilterDrawerOpen(false)}>Cancel</GoabButton>
          </GoabButtonGroup>
        }
      >
        <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--goa-space-l)' }}>
          <GoabFormItem label="Status">
            <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--goa-space-xs)' }}>
              {filterOptions.statuses.map(status => (
                <GoabCheckbox key={status} name={`status-${status}`} text={status}
                  checked={pendingFilters.status.includes(status)}
                  onChange={() => togglePendingFilter('status', status)} />
              ))}
            </div>
          </GoabFormItem>
          <GoabFormItem label="Priority">
            <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--goa-space-xs)' }}>
              {filterOptions.priorities.map(p => (
                <GoabCheckbox key={p} name={`priority-${p}`} text={p.charAt(0).toUpperCase() + p.slice(1)}
                  checked={pendingFilters.priority.includes(p)}
                  onChange={() => togglePendingFilter('priority', p)} />
              ))}
            </div>
          </GoabFormItem>
          <GoabFormItem label="Assigned to">
            <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--goa-space-xs)' }}>
              {filterOptions.assignees.map(a => (
                <GoabCheckbox key={a} name={`assignee-${a}`} text={a}
                  checked={pendingFilters.assignedTo.includes(a)}
                  onChange={() => togglePendingFilter('assignedTo', a)} />
              ))}
            </div>
          </GoabFormItem>
          {Object.values(pendingFilters).some(arr => arr.length > 0) && (
            <><GoabDivider />
            <GoabButton type="tertiary" size="compact" onClick={() => setPendingFilters({ status: [], priority: [], assignedTo: [] })}>Clear all</GoabButton></>
          )}
        </div>
      </GoabDrawer>

      {/* Delete modal */}
      <GoabModal heading="Delete case" open={showDeleteModal} calloutVariant="emergency"
        actions={
          <GoabButtonGroup alignment="end">
            <GoabButton type="tertiary" size="compact" onClick={() => setShowDeleteModal(false)}>Cancel</GoabButton>
            <GoabButton type="primary" size="compact" variant="destructive" onClick={confirmDelete}>Delete</GoabButton>
          </GoabButtonGroup>
        }
      >
        <GoabText mt="none" mb="none">Are you sure you want to delete this case? This action cannot be undone.</GoabText>
      </GoabModal>
    </div>
  );
}
